"""
codebench_debug — visual-debugger backend for CodeBench
═══════════════════════════════════════════════════════

A Pdb subclass that talks to the Swift-side debugger UI via signal
files instead of stdin/stdout. The UI gets:

  • a live "where am I" indicator (file + line) painted in Monaco's
    gutter as a golden arrow
  • a variable inspector populated from `frame.f_locals` and
    `frame.f_globals`
  • a call-stack panel from `frame.f_back` chain

And sends back commands:

  • Continue   (run until next breakpoint or end)
  • Step Over  (next line, don't enter calls)
  • Step Into  (next line, enter calls)
  • Step Out   (run until current frame returns)
  • Stop       (terminate the debug session)

Signal-file protocol — both files live in `$TMPDIR/latex_signals/`:

  debug_state.json   ← Python writes after every stop. Shape:
      {
        "file": "/abs/path/to/script.py",
        "line": 42,
        "stack": [{"file": "...", "line": ..., "func": "..."}, ...],
        "locals":   {"x": "1", "y": "'hello'", ...},   # values are repr()-clipped
        "globals":  {"NAME": "value", ...},
        "status": "stopped" | "running" | "done"
      }

  debug_command.txt  ← Swift writes. One of:
      continue / step / next / return / quit /
      eval:<expression>  (Python evaluates in current frame, result
                          goes back into debug_eval_result.txt)

Usage from the shell:
    debug-gui script.py [args...]

The CLI `debug` builtin keeps the plain pdb behavior; `debug-gui` is
the visual variant.
"""

import bdb
import json
import os
import pdb
import sys
import tempfile
import threading
import time
import traceback
from typing import Any, Dict, List, Optional


def _signal_dir() -> str:
    d = os.path.join(tempfile.gettempdir(), "latex_signals")
    os.makedirs(d, exist_ok=True)
    return d


def _state_path() -> str:    return os.path.join(_signal_dir(), "debug_state.json")
def _cmd_path() -> str:      return os.path.join(_signal_dir(), "debug_command.txt")
def _eval_path() -> str:     return os.path.join(_signal_dir(), "debug_eval_result.txt")


# ─── repr clipping ────────────────────────────────────────────────

_MAX_VALUE_LEN = 200    # chars per variable value
_MAX_VAR_COUNT = 200    # don't ship more than this many vars per scope

def _safe_repr(v: Any) -> str:
    """Short, exception-safe repr for the inspector. Long values get
    clipped with `…`. Non-repr-able objects fall back to their type."""
    try:
        s = repr(v)
    except Exception as e:
        return "<unrepr-able: %s>" % type(v).__name__
    if len(s) > _MAX_VALUE_LEN:
        s = s[:_MAX_VALUE_LEN] + "…"
    return s


def _snapshot_frame(frame) -> Dict[str, str]:
    """Repr-snapshot of a frame's locals (with private __* stripped)."""
    out: Dict[str, str] = {}
    if frame is None:
        return out
    items = list(frame.f_locals.items())
    items.sort(key=lambda kv: kv[0])
    n = 0
    for k, v in items:
        if k.startswith("__") and k.endswith("__"):
            continue
        out[k] = _safe_repr(v)
        n += 1
        if n >= _MAX_VAR_COUNT:
            out["…"] = "(truncated: %d more)" % (len(items) - n)
            break
    return out


def _snapshot_stack(frame) -> List[Dict[str, Any]]:
    """Walk frame.f_back, returning (file, line, func) for each."""
    stack: List[Dict[str, Any]] = []
    f = frame
    depth = 0
    while f is not None and depth < 50:
        stack.append({
            "file": f.f_code.co_filename,
            "line": f.f_lineno,
            "func": f.f_code.co_name,
        })
        f = f.f_back
        depth += 1
    return stack


# ─── The debugger ─────────────────────────────────────────────────

class _GUIDebugger(pdb.Pdb):
    """Pdb subclass that surfaces state through signal files and reads
    commands from same. The interactive cmdloop is bypassed — every
    "stop" point dumps state and busy-waits for a command file."""

    def __init__(self, script_path: str):
        # `stdin=os.devnull` so the parent pdb's input prompts don't
        # interleave with our shell's prompt if anyone accidentally
        # falls back to cmdloop.
        super().__init__(stdin=open(os.devnull, "r"), stdout=sys.stdout)
        self.script_path = script_path
        self.prompt = ""    # don't print "(Pdb)" — we have a real UI
        self._waiting_cmd = False
        # Clean up any stale command file from previous runs.
        for p in (_cmd_path(), _eval_path()):
            try:
                if os.path.exists(p): os.remove(p)
            except OSError:
                pass

    # ── State publishing ──────────────────────────────────────────

    def _publish(self, status: str = "stopped", extra: Optional[Dict] = None):
        if self.curframe is None:
            return
        state: Dict[str, Any] = {
            "file":    self.curframe.f_code.co_filename,
            "line":    self.curframe.f_lineno,
            "func":    self.curframe.f_code.co_name,
            "stack":   _snapshot_stack(self.curframe),
            "locals":  _snapshot_frame(self.curframe),
            "globals": _snapshot_globals(self.curframe),
            "status":  status,
        }
        if extra:
            state.update(extra)
        # Atomic write — Swift's vnode watcher fires on rename.
        path = _state_path()
        tmp = path + ".tmp"
        try:
            with open(tmp, "w", encoding="utf-8") as f:
                json.dump(state, f)
            os.replace(tmp, path)
        except OSError:
            pass

    # ── Stop hooks (called by bdb when execution pauses) ──────────

    def user_line(self, frame):
        self.curframe = frame
        self._publish(status="stopped")
        self._await_command(frame)

    def user_return(self, frame, return_value):
        self.curframe = frame
        extra = {"return_value": _safe_repr(return_value)}
        self._publish(status="stopped", extra=extra)
        self._await_command(frame)

    def user_exception(self, frame, exc_info):
        self.curframe = frame
        et, ev, tb = exc_info
        extra = {"exception": "%s: %s" % (et.__name__, ev)}
        self._publish(status="stopped", extra=extra)
        self._await_command(frame)

    # ── Command loop replacement ──────────────────────────────────

    # First wait at the entry stop is the "headless probe" — if no
    # Swift UI sends a command within HEADLESS_TIMEOUT seconds, we
    # assume nothing is listening (e.g. user ran `debug-gui` after
    # editing the file in Monaco but before the Xcode build that
    # ships DebuggerUI). In that case we silently `set_continue()`
    # and let the script run to completion — same UX as `python`.
    _HEADLESS_TIMEOUT = 3.0
    _ui_responsive = False  # flips True after the first received command

    def _await_command(self, frame):
        """Spin-poll the command file. ~50 ms latency on key press.

        Falls back to auto-continue if no command arrives in
        HEADLESS_TIMEOUT seconds *and* this is the very first stop
        (the Swift UI isn't listening). Once a real command has been
        seen, subsequent stops wait forever — at that point we know
        the UI is alive and the user is actively stepping.
        """
        cmd_path = _cmd_path()
        # Drain any stale command first (else we'd process old presses)
        try:
            if os.path.exists(cmd_path): os.remove(cmd_path)
        except OSError:
            pass

        started = time.time()
        while True:
            try:
                if not os.path.exists(cmd_path):
                    # Headless fallback — only at the FIRST stop, before
                    # any UI activity has been confirmed.
                    if not self._ui_responsive and \
                       (time.time() - started) > self._HEADLESS_TIMEOUT:
                        sys.stderr.write(
                            "[debug-gui] no UI response after %ds — "
                            "running script to completion. "
                            "(Open CodeBench's editor + tap Step/Continue "
                            "to drive the debugger; re-run after Xcode "
                            "rebuild for the visual toolbar.)\n"
                            % int(self._HEADLESS_TIMEOUT))
                        self.set_continue(); return
                    time.sleep(0.05)
                    continue
                with open(cmd_path, "r", encoding="utf-8") as f:
                    cmd = f.read().strip()
                try: os.remove(cmd_path)
                except OSError: pass

                if not cmd:
                    continue
                # Mark UI as responsive — no more headless fallback
                # for the rest of this session.
                self._ui_responsive = True
                if cmd == "continue":
                    self.set_continue(); return
                if cmd == "step":
                    self.set_step(); return
                if cmd == "next":
                    self.set_next(frame); return
                if cmd == "return":
                    self.set_return(frame); return
                if cmd == "quit":
                    self.set_quit(); return
                if cmd.startswith("eval:"):
                    expr = cmd[5:]
                    self._handle_eval(frame, expr)
                    continue
                # Unknown command — log and keep waiting.
                sys.stderr.write("[codebench_debug] unknown cmd: %r\n" % cmd)
            except KeyboardInterrupt:
                # User hit Ctrl+C — escape the debugger entirely.
                sys.stderr.write("\n[debug-gui] interrupted by user\n")
                self.set_quit(); return
            except Exception as e:
                sys.stderr.write("[codebench_debug] await loop error: %s\n" % e)
                time.sleep(0.1)

    def _handle_eval(self, frame, expr: str):
        """Evaluate `expr` in the current frame and write the result
        to debug_eval_result.txt for the Swift watch panel to pick up."""
        try:
            val = eval(expr, frame.f_globals, frame.f_locals)
            result = _safe_repr(val)
        except Exception as e:
            result = "Error: %s: %s" % (type(e).__name__, e)
        try:
            tmp = _eval_path() + ".tmp"
            with open(tmp, "w", encoding="utf-8") as f:
                f.write(result)
            os.replace(tmp, _eval_path())
        except OSError:
            pass


def _snapshot_globals(frame) -> Dict[str, str]:
    """Globals that aren't builtins/dunders/modules — what the user
    actually defined at the top level."""
    out: Dict[str, str] = {}
    if frame is None:
        return out
    g = frame.f_globals
    # Skip if same as locals (we'd double-report)
    if g is frame.f_locals:
        return out
    keys = sorted(g.keys())
    n = 0
    for k in keys:
        if k.startswith("__") and k.endswith("__"):
            continue
        v = g[k]
        # Skip modules and module-level functions imported via `from ... import`
        # (user usually doesn't care about those at debug time).
        if type(v).__name__ == "module":
            continue
        out[k] = _safe_repr(v)
        n += 1
        if n >= _MAX_VAR_COUNT:
            out["…"] = "(truncated: %d more)" % (len(keys) - n)
            break
    return out


# ─── Public entry point ───────────────────────────────────────────

def run_with_gui(script_path: str, script_args: List[str],
                 saved_breakpoints: Optional[List[int]] = None) -> int:
    """Run `script_path` under the GUI debugger. Returns process-style
    exit status: 0 = normal, 1 = exception, 130 = user quit (Ctrl-C
    convention), -1 = launch error."""
    if not os.path.isfile(script_path):
        return -1

    dbg = _GUIDebugger(script_path)
    # Apply saved breakpoints — Swift side reads ~/.codebench/breakpoints/
    # and passes them in here. Setting via bdb.set_break (not just
    # adding to bdb.Breakpoint.bplist) so the debugger actually stops.
    if saved_breakpoints:
        for ln in saved_breakpoints:
            try:
                dbg.set_break(script_path, int(ln))
            except Exception:
                pass

    # Publish "running" so the UI knows we've launched.
    try:
        with open(_state_path(), "w", encoding="utf-8") as f:
            json.dump({
                "file": script_path, "line": 1, "stack": [],
                "locals": {}, "globals": {},
                "status": "running"
            }, f)
    except OSError:
        pass

    old_argv = sys.argv[:]
    sys.argv = [script_path, *script_args]
    exit_status = 0
    # Save + reset __main__ so the script runs as the top-level module.
    # (Mirrors what pdb's private _runscript does, but we can't rely on
    # that method existing — it's `_underscored` and varies between
    # Python versions / vendored builds.)
    import __main__
    saved_main = __main__.__dict__.copy()
    __main__.__dict__.clear()
    __main__.__dict__.update({
        "__name__":     "__main__",
        "__file__":     script_path,
        "__builtins__": __builtins__,
        "__spec__":     None,
    })
    # Bdb's _wait_for_mainpyfile dance — stop stopping at lines in
    # bdb/pdb internals before user code actually starts.
    dbg._wait_for_mainpyfile = True
    dbg.mainpyfile = dbg.canonic(script_path)
    dbg._user_requested_quit = False
    try:
        with open(script_path, "rb") as f:
            src = f.read()
        code_obj = compile(src, script_path, "exec")
        dbg.run(code_obj)
    except SystemExit as e:
        exit_status = int(e.code or 0)
    except bdb.BdbQuit:
        exit_status = 130
    except KeyboardInterrupt:
        exit_status = 130
    except Exception:
        traceback.print_exc()
        exit_status = 1
    finally:
        # Restore __main__ for the shell.
        __main__.__dict__.clear()
        __main__.__dict__.update(saved_main)
        sys.argv = old_argv
        # Publish "done" so the UI dismisses the debugger toolbar.
        try:
            with open(_state_path(), "w", encoding="utf-8") as f:
                json.dump({
                    "file": script_path, "line": 0, "stack": [],
                    "locals": {}, "globals": {},
                    "status": "done",
                    "exit_status": exit_status,
                }, f)
        except OSError:
            pass
    return exit_status
